const raw = $input.item.json;
const source = raw.source_tool || 'fireflies';

// Normalize to standard schema regardless of source tool
let normalized = {};

if (source === 'fireflies') {
  const t = raw?.data?.transcript || raw;
  normalized = {
    transcript_id: t.id,
    title: t.title,
    date: t.date,
    duration_minutes: Math.round((t.duration || 0) / 60),
    attendees: (t.participants || []).map(p => ({ name: p.name, email: p.email })),
    speakers: (t.sentences || []).map(s => ({ speaker: s.speaker_name, text: s.text })),
    full_text: t.transcript || (t.sentences || []).map(s => s.speaker_name + ': ' + s.text).join('\n'),
    source_tool: 'fireflies',
    source_url: t.meeting_link || ''
  };
} else if (source === 'gong') {
  const c = raw?.call || raw;
  normalized = {
    transcript_id: c.id,
    title: c.title,
    date: c.started,
    duration_minutes: Math.round((c.duration || 0) / 60),
    attendees: (c.parties || []).map(p => ({ name: p.name, email: p.emailAddress })),
    speakers: (c.transcript || []).flatMap(seg => (seg.sentences || []).map(s => ({ speaker: seg.speakerName, text: s.text }))),
    full_text: (c.transcript || []).flatMap(seg => (seg.sentences || []).map(s => seg.speakerName + ': ' + s.text)).join('\n'),
    source_tool: 'gong',
    source_url: c.url || ''
  };
} else if (source === 'fathom') {
  const f = raw?.recording || raw;
  normalized = {
    transcript_id: f.id,
    title: f.title,
    date: f.created_at,
    duration_minutes: f.duration_minutes || 0,
    attendees: (f.attendees || []).map(p => ({ name: p.name, email: p.email })),
    speakers: (f.transcript_lines || []).map(l => ({ speaker: l.speaker, text: l.text })),
    full_text: (f.transcript_lines || []).map(l => l.speaker + ': ' + l.text).join('\n'),
    source_tool: 'fathom',
    source_url: f.share_url || ''
  };
}

return normalized;

const transcript = $input.item.json;

// Reduce token count: strip filler, timestamps, truncate to ~12k tokens
let text = transcript.full_text || '';

// Remove common filler patterns
text = text
  .replace(/\b(um+|uh+|hmm+|like,?\s+like|you know|sort of|kind of)\b/gi, '')
  .replace(/\[silence\]|\[noise\]|\[crosstalk\]|\[inaudible\]/gi, '')
  .replace(/\d{2}:\d{2}:\d{2}\.\d+/g, '')
  .replace(/\s{2,}/g, ' ')
  .trim();

// Truncate: keep first 8k + last 4k chars (~12k token approx)
const MAX = 48000; // ~12k tokens * 4 chars/token
if (text.length > MAX) {
  const head = text.slice(0, 32000);
  const tail = text.slice(-16000);
  text = head + '\n\n[... middle portion summarized for token efficiency ...]\n\n' + tail;
}

return {
  ...transcript,
  cleaned_text: text,
  original_length: transcript.full_text?.length || 0,
  cleaned_length: text.length
};

const response = $input.item.json;

// Extract text from Anthropic response
const rawText = response?.content?.[0]?.text || '';

let parsed = null;
try {
  // Strip markdown code fences if present
  const clean = rawText.replace(/```json\n?|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch (e) {
  // Return with error flag for manual review
  return {
    ...$input.item.json,
    ai_parse_error: true,
    ai_raw_response: rawText,
    summary: null,
    action_items: [],
    decisions: [],
    commitments: [],
    key_topics: [],
    themes: [],
    sentiment: 'unknown',
    open_questions: []
  };
}

return {
  ...$input.item.json,
  ai_parse_error: false,
  summary: parsed.summary || '',
  action_items: parsed.action_items || [],
  decisions: parsed.decisions || [],
  commitments: parsed.commitments || [],
  key_topics: parsed.key_topics || [],
  themes: parsed.themes || [],
  sentiment: parsed.sentiment || 'neutral',
  open_questions: parsed.open_questions || []
};

const data = $input.item.json;
const emails = $input.all().filter(i => i.json.threadId).map(i => ({
  subject: i.json.snippet ? i.json.snippet.slice(0, 200) : '',
  date: i.json.internalDate ? new Date(parseInt(i.json.internalDate)).toISOString() : ''
}));

return {
  ...data,
  email_context: emails,
  followup_status: emails.length > 0 ? 'email_context_found' : 'no_email_context'
};

