const item = $input.item.json;
const runId = $execution.id;

console.log(JSON.stringify({
  run_id: runId,
  timestamp: new Date().toISOString(),
  transcript_id: item.transcript_id,
  source_tool: item.source_tool,
  outcome: item.ai_parse_error ? 'processed_with_ai_error' : 'success',
  steps: {
    fetch: 'ok',
    normalize: 'ok',
    crm_lookup: item.company_id ? 'linked' : 'unlinked',
    ai_processing: item.ai_parse_error ? 'parse_error' : 'ok',
    email_enrichment: (item.email_context || []).length > 0 ? 'enriched' : 'skipped',
    storage: 'ok'
  },
  action_items_count: (item.action_items || []).length,
  themes: item.themes || [],
  sentiment: item.sentiment
}));

return item;
